__kernel void kernel_gpu_opencl(
    par_str par,
    dim_str dim,
    __global box_str* box,
    __global FOUR_VECTOR* rv,
    __global fp* qv,
    __global FOUR_VECTOR* fv)
{
    int l = get_global_id(0) / NUMBER_PAR_PER_BOX;
    int local_i = get_global_id(0) % NUMBER_PAR_PER_BOX;

    if (l >= dim.number_boxes) return;

    fp alpha = par.alpha;
    fp a2 = 2.0 * alpha * alpha;

    long first_i = box[l].offset;
    FOUR_VECTOR rA = rv[first_i + local_i];
    FOUR_VECTOR fA = fv[first_i + local_i];

    int nn = box[l].nn;

    for (int k = 0; k <= nn; k++) {
        int pointer;
        if (k == 0) {
            pointer = l;
        } else {
            pointer = box[l].nei[k-1].number;
        }

        long first_j = box[pointer].offset;

        for (int j = 0; j < NUMBER_PAR_PER_BOX; j++) {
            FOUR_VECTOR rB = rv[first_j + j];
            fp qB = qv[first_j + j];

            fp r2 = rA.v + rB.v - DOT(rA, rB);
            fp u2 = a2 * r2;
            fp vij = exp(-u2);
            fp fs = 2.0 * vij;

            THREE_VECTOR d;
            d.x = rA.x - rB.x;
            d.y = rA.y - rB.y;
            d.z = rA.z - rB.z;

            fp fxij = fs * d.x;
            fp fyij = fs * d.y;
            fp fzij = fs * d.z;

            fA.v += qB * vij;
            fA.x += qB * fxij;
            fA.y += qB * fyij;
            fA.z += qB * fzij;
        }
    }

    fv[first_i + local_i] = fA;
}
